#include<bits/stdc++.h>using namespace std;priority_queue<int,vector<int>,greater<int>> p;int n,m;int main(){    cin>>n>>m;    for(int i=1;i<=n;i++){        int a;        cin>>a;        p.push(a);     }    for(int i=1;i<=m;i++){        int b;        cin>>b;        if(b>=0){          p.push(b);        }else{            int sb=abs(b);            vector<int> vec;            for(int i=1;i<sb;i++){                vec.push_back(p.top());                p.pop();            }            p.pop();            while(vec.size()){                p.push(vec.back());                vec.pop_back();            }        }    }    if(p.size()==0){        cout<<0;    }else{        cout<<p.top();    }    return 0;}